const input = $input.first().json;
const rows = Array.isArray(input) ? input : (input.data || input.results || input.publishers || []);
const relevant = ['cbd','wellness','fitness','supplement','recovery','health','lifestyle','coupon','deal','review'];
const now = new Date().toISOString();
const lowClickThreshold = Number($vars.LOW_PERFORMER_CLICKS || 150);
const topSalesThreshold = Number($vars.TOP_PERFORMER_SALES || 10);
const strongCr = Number($vars.TOP_PERFORMER_CR || 0.03);
const lowCr = Number($vars.LOW_PERFORMER_CR || 0.005);
const affiliates = rows.map(r => {
  const clicks = Number(r.clicks || r.totalClicks || r.clickCount || 0);
  const sales = Number(r.sales || r.transactions || r.saleCount || 0);
  const cr = Number(r.conversionRate || r.cr || (clicks ? sales / clicks : 0));
  const category = String(r.category || r.vertical || '').toLowerCase();
  const country = r.country || r.countryCode || '';
  const name = r.affiliateName || r.publisherName || r.name || '';
  const website = r.websiteUrl || r.website || r.url || '';
  let classification = 'MONITOR';
  if (clicks >= lowClickThreshold && sales === 0 && cr <= lowCr) classification = 'LOW_PERFORMER';
  if (sales >= topSalesThreshold && cr >= strongCr) classification = 'TOP_PERFORMER';
  const isRelevant = relevant.some(k => `${category} ${name} ${website}`.toLowerCase().includes(k));
  if (classification === 'MONITOR' && isRelevant) classification = 'OUTREACH_CANDIDATE';
  return { affiliate_id: r.affiliateId || r.publisherId || r.id || '', affiliate_name: name, clicks, sales, conversion_rate: cr, website_url: website, category, country, classification, source: 'AWIN', last_seen_at: now };
});
const values = affiliates.map(a => [a.affiliate_id, a.affiliate_name, a.clicks, a.sales, a.conversion_rate, a.website_url, a.category, a.country, a.classification, a.source, a.last_seen_at]);
return [{ json: { count: affiliates.length, affiliates, sheetsPayload: { valueInputOption: 'USER_ENTERED', data: [{ range: 'affiliates!A2:K', majorDimension: 'ROWS', values }] } } }];

const queries = [
  'wellness blog affiliate CBD', 'CBD blog product reviews', 'fitness influencer recovery supplements',
  'supplement website product reviews', 'recovery website wellness', 'ecommerce review site CBD',
  'coupon site wellness CBD', 'deal site supplements', 'lifestyle publisher wellness products'
];
return queries.map((query, i) => ({ json: { query, niche_seed: query.split(' ')[0], maxResults: Number($vars.DISCOVERY_RESULTS_PER_QUERY || 50), runKey: `${new Date().toISOString().slice(0,10)}-${i}` } }));

const seen = new Set();
const now = new Date().toISOString();
const rows = [];
for (const item of $input.all()) {
  const data = Array.isArray(item.json) ? item.json : (item.json.organicResults || item.json.results || item.json.items || []);
  for (const r of data) {
    const url = r.url || r.link || r.displayedUrl || '';
    if (!url) continue;
    let domain = '';
    try { domain = new URL(url.startsWith('http') ? url : `https://${url}`).hostname.replace(/^www\./,'').toLowerCase(); } catch { continue; }
    if (seen.has(domain)) continue;
    seen.add(domain);
    rows.push({ lead_id: domain, domain, website_url: url, company_name: r.title || '', author_name: '', email: '', contact_page: '', social_links: '', niche_category: item.json.niche_seed || '', source: 'Apify discovery', discovery_query: item.json.query || '', status: 'NEW', created_at: now, last_checked_at: now });
  }
}
const values = rows.map(l => [l.lead_id,l.domain,l.website_url,l.company_name,l.author_name,l.email,l.contact_page,l.social_links,l.niche_category,l.source,l.discovery_query,l.status,l.created_at,l.last_checked_at]);
return [{ json: { count: rows.length, leads: rows, sheetsPayload: { range: 'scraped_leads!A2:N', majorDimension: 'ROWS', values } } }];

const values = $input.first().json.values || [];
const headers = values[0] || [];
const rows = values.slice(1).map(row => Object.fromEntries(headers.map((h,i)=>[h,row[i]||''])));
const eligible = rows.filter(r => ['NEW','NEEDS_ENRICHMENT',''].includes(String(r.status || '').toUpperCase())).slice(0, Number($vars.ENRICHMENT_BATCH_SIZE || 100));
return eligible.map(r => ({ json: { ...r, startUrls: [{ url: r.website_url }], maxPages: 6 } }));

const emailRegex = /[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi;
const socialRegex = /https?:\/\/(www\.)?(linkedin|instagram|facebook|x|twitter|tiktok)\.com\/[^\s"'<>]+/gi;
const now = new Date().toISOString();
const out = [];
for (const item of $input.all()) {
  const pages = Array.isArray(item.json) ? item.json : [item.json];
  const blob = pages.map(p => `${p.url || ''}\n${p.text || ''}\n${p.markdown || ''}\n${p.html || ''}`).join('\n');
  const emails = [...new Set((blob.match(emailRegex) || []).map(e => e.toLowerCase()).filter(e => !e.includes('example.') && !e.includes('sentry.') && !e.includes('wixpress.')))];
  const preferred = emails.find(e => /partnership|partner|affiliate|marketing|collab|business/.test(e)) || emails[0] || '';
  const socials = [...new Set(blob.match(socialRegex) || [])].slice(0, 10).join(', ');
  const contactPage = (pages.find(p => /contact|partner|advertise|about/i.test(p.url || '')) || {}).url || '';
  out.push({ json: { email: preferred, all_emails: emails.join(', '), social_links: socials, contact_page: contactPage, enrichment_status: preferred ? 'ENRICHED' : 'NO_EMAIL', enriched_at: now } });
}
const values = out.map(i => [i.json.email,i.json.all_emails,i.json.contact_page,i.json.social_links,i.json.enrichment_status,i.json.enriched_at]);
return [{ json: { count: out.length, enriched: out.map(i=>i.json), sheetsPayload: { values } } }];

const values = $input.first().json.values || [];
const headers = values[0] || [];
const rows = values.slice(1).map(row => Object.fromEntries(headers.map((h,i)=>[h,row[i]||''])));
const approved = rows.filter(r => String(r.approval_status || '').toUpperCase() === 'APPROVED' && !r.generated_at).slice(0, Number($vars.AI_BATCH_SIZE || 50));
return approved.map(r => {
  const type = String(r.email_type || r.classification || 'NEW_OUTREACH').toUpperCase().includes('LOW') ? 'LOW_PERFORMER' : 'NEW_OUTREACH';
  const facts = JSON.stringify(r);
  const prompt = type === 'LOW_PERFORMER'
    ? `Write a short helpful affiliate optimization email for an existing Greenroads affiliate. Use these facts: ${facts}. Mention best-selling Greenroads products, conversion optimization ideas, banner/creative suggestions, and coupon opportunities. Return JSON with subject,intro,body,cta,follow_up_1,follow_up_2.`
    : `Write a short personalized recruitment email for a potential Greenroads affiliate. Use these facts: ${facts}. Mention affiliate commissions, wellness/CBD market fit, why their audience matches Greenroads, and an AWIN partnership CTA. Return JSON with subject,intro,body,cta,follow_up_1,follow_up_2.`;
  return { json: { ...r, email_type: type, prompt } };
});

const now = new Date().toISOString();
const values = [];
for (const item of $input.all()) {
  const choice = item.json.choices?.[0]?.message?.content || '{}';
  let copy = {};
  try { copy = JSON.parse(choice); } catch { copy = { subject: 'Greenroads affiliate partnership', body: choice }; }
  values.push([item.json.email || item.json.business_email || '', item.json.domain || '', item.json.email_type || 'NEW_OUTREACH', copy.subject || '', `${copy.intro || ''}\n\n${copy.body || ''}\n\n${copy.cta || ''}`.trim(), copy.follow_up_1 || '', copy.follow_up_2 || '', 'READY_TO_SEND', now]);
}
return [{ json: { sheetsPayload: { values } } }];

const values = $input.first().json.values || [];
const headers = values[0] || [];
const rows = values.slice(1).map((row, idx) => ({ row_number: idx + 2, ...Object.fromEntries(headers.map((h,i)=>[h,row[i]||''])) }));
const now = new Date();
const sentDomains = new Map();
for (const r of rows) {
  const domain = String(r.domain || '').toLowerCase();
  if (r.sent_date && domain) sentDomains.set(domain, new Date(r.sent_date));
}
const limit = Number($vars.GMAIL_SEND_LIMIT_PER_RUN || 40);
const due = [];
for (const r of rows) {
  const status = String(r.status || '').toUpperCase();
  const response = String(r.response_status || '').toUpperCase();
  const email = String(r.email || '').toLowerCase();
  const domain = String(r.domain || '').toLowerCase();
  let include = true;
  if (!email || response === 'REPLIED' || status === 'REPLIED' || status === 'BLACKLISTED') include = false;
  if (include && status === 'READY_TO_SEND') include = true;
  else if (include && status === 'SENT' && r.sent_date) include = (now - new Date(r.sent_date)) / 86400000 >= 5 && !r.followup_1_sent_at;
  else if (include && status === 'FOLLOWUP_1_SENT' && r.followup_1_sent_at) include = (now - new Date(r.followup_1_sent_at)) / 86400000 >= 10 && !r.followup_2_sent_at;
  else if (include) {
    const last = sentDomains.get(domain);
    include = !last || (now - last) / 86400000 >= Number($vars.DOMAIN_COOLDOWN_DAYS || 45);
  }
  if (include) due.push(r);
  if (due.length >= limit) break;
}
return due.map(r => {
  const status = String(r.status || '').toUpperCase();
  const followupNumber = status === 'SENT' ? 1 : (status === 'FOLLOWUP_1_SENT' ? 2 : 0);
  const body = followupNumber === 1 ? r.follow_up_1 : (followupNumber === 2 ? r.follow_up_2 : r.body);
  return { json: { ...r, followupNumber, send_body: body, send_subject: followupNumber ? `Re: ${r.subject}` : r.subject } };
});

const original = $('Dedupe and Build Send Queue').all();
const replyChecks = $input.all();
const sendable = [];
for (let i = 0; i < original.length; i++) {
  const reply = replyChecks[i]?.json || {};
  const hasReply = Boolean(reply.id || reply.threadId || reply.messages?.length);
  if (!hasReply) sendable.push({ json: original[i].json, pairedItem: { item: i } });
}
return sendable;
